import{_ as e,c as a,o as n,ae as i}from"./chunks/framework.CeIuOzFV.js";const g=JSON.parse('{"title":"AI Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"user-manual/settings/ai.md","filePath":"user-manual/settings/ai.md"}'),o={name:"user-manual/settings/ai.md"};function r(l,t,s,d,c,u){return n(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="ai-configuration" tabindex="-1">AI Configuration <a class="header-anchor" href="#ai-configuration" aria-label="Permalink to &quot;AI Configuration&quot;">​</a></h1><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>The AI configuration page allows you to set up Artivact&#39;s artificial intelligence integration for features like automatic translation and text-to-speech (TTS) audio generation.</p><p>The page is available from the system settings menu and can only be accessed by administrators.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>The following configuration options are available:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;">Enable AI</td><td style="text-align:left;">Enables or disables all AI features in the application.</td></tr><tr><td style="text-align:left;">API Key</td><td style="text-align:left;">The API key for authenticating with the AI service (e.g. OpenAI).</td></tr><tr><td style="text-align:left;">Translation Prompt</td><td style="text-align:left;">A prompt template used for automatic translations. The placeholder <code>{locale}</code> will be replaced by the target locale. See <a href="./../content-management/internationalization.html">I18N</a> for more details on translations.</td></tr><tr><td style="text-align:left;">TTS Voice</td><td style="text-align:left;">The voice identifier used for text-to-speech audio generation (e.g. <code>alloy</code>).</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">API Key</p><p>The API key is required for all AI features to work. Without a valid API key, automatic translation and audio generation will not be available.</p></div><h2 id="automatic-translation" tabindex="-1">Automatic Translation <a class="header-anchor" href="#automatic-translation" aria-label="Permalink to &quot;Automatic Translation&quot;">​</a></h2><p>When AI is enabled and configured, Artivact can automatically translate item texts and page content into the configured locales using the AI service.</p><p>The translation is based on the <strong>Translation Prompt</strong>. You can customize the prompt template to influence how the AI performs translations.</p><p>See <a href="./../content-management/internationalization.html">I18N</a> for details on managing multilingual content.</p><h2 id="audio-content-generation-tts" tabindex="-1">Audio Content Generation (TTS) <a class="header-anchor" href="#audio-content-generation-tts" aria-label="Permalink to &quot;Audio Content Generation (TTS)&quot;">​</a></h2><p>When AI is enabled and configured, Artivact can generate audio content from text using text-to-speech.</p><p>The audio generation is based on the configured <strong>TTS Voice</strong>. The generated audio files can be used e.g. in content exports.</p><p>The available voices depend on the configured AI provider.</p>',16)])])}const f=e(o,[["render",r]]);export{g as __pageData,f as default};
